agent_output:
{
  "executive_summary": "A food delivery platform architecture built around four bounded contexts — Order Management (core), Restaurant (supporting), Delivery (core), and Customer/Identity (generic) — using an event-driven microservices approach with synchronous APIs at the edges and asynchronous domain events for inter-service coordination. The design prioritizes independent deployability, real-time state tracking, and clear ownership boundaries to support the three-sided marketplace of restaurants, customers, and delivery drivers.",

  "architecture": {
    "components": [
      {
        "name": "API Gateway",
        "responsibility": "Single entry point for all clients (customer app, restaurant dashboard, driver app). Handles authentication, rate limiting, request routing, and protocol translation.",
        "boundaries": "Stateless. No business logic. Routes to downstream services. Owns SSL termination and API versioning."
      },
      {
        "name": "Order Service",
        "responsibility": "Manages the full order lifecycle: creation, payment authorization, restaurant acceptance, preparation tracking, driver assignment, delivery confirmation, and completion. Owns the Order aggregate.",
        "boundaries": "Owns orders table. Publishes OrderPlaced, OrderAccepted, OrderReady, OrderDelivered events. Orchestrates the order saga."
      },
      {
        "name": "Restaurant Service",
        "responsibility": "Manages restaurant profiles, menus, availability, operating hours, and prep-time estimates. Handles menu CRUD and restaurant onboarding.",
        "boundaries": "Owns restaurant and menu data. Publishes MenuUpdated, RestaurantOnline/Offline events. Does NOT own order state."
      },
      {
        "name": "Delivery Service",
        "responsibility": "Manages driver profiles, real-time location tracking, driver availability, route optimization, and delivery assignment. Implements the matching algorithm between available drivers and pending orders.",
        "boundaries": "Owns driver state and location data. Publishes DriverAssigned, DriverLocationUpdated, DeliveryCompleted events. Consumes OrderReady events."
      },
      {
        "name": "Customer Service",
        "responsibility": "Manages customer profiles, addresses, preferences, and order history views. Handles registration and profile management.",
        "boundaries": "Owns customer profile data. Read-model for order history (projected from Order events)."
      },
      {
        "name": "Payment Service",
        "responsibility": "Handles payment authorization, capture, refunds, and driver/restaurant payouts. Integrates with external payment processor (Stripe, etc.).",
        "boundaries": "Owns payment transaction records. Publishes PaymentAuthorized, PaymentCaptured, RefundIssued events. Anti-corruption layer to external payment provider."
      },
      {
        "name": "Notification Service",
        "responsibility": "Sends push notifications, SMS, and emails to all three user types. Reacts to domain events to trigger contextual notifications (order updates, driver arrival, promotions).",
        "boundaries": "Stateless event consumer. Owns notification templates and delivery preferences. No business logic — pure reaction to events."
      },
      {
        "name": "Search & Discovery Service",
        "responsibility": "Powers restaurant search, filtering, ranking, and recommendation. Maintains a denormalized read model optimized for search queries.",
        "boundaries": "Read-only projection of restaurant and menu data. Owns search index (Elasticsearch or similar). Consumes MenuUpdated, RestaurantOnline events."
      },
      {
        "name": "Pricing & Promotions Service",
        "responsibility": "Calculates delivery fees, surge pricing, applies promo codes, and manages discount campaigns.",
        "boundaries": "Stateless calculation engine plus promotion state. Publishes PriceCalculated events. Consumed synchronously by Order Service during checkout."
      },
      {
        "name": "Rating & Review Service",
        "responsibility": "Manages ratings for restaurants, menu items, and drivers. Calculates aggregate scores.",
        "boundaries": "Owns review data. Publishes RatingSubmitted events. Consumed by Search service for ranking."
      }
    ],
    "interfaces": [
      {
        "from": "API Gateway",
        "to": "Order Service",
        "contract": "REST/gRPC — POST /orders, GET /orders/{id}, PATCH /orders/{id}/status",
        "coupling_type": "runtime (synchronous)"
      },
      {
        "from": "API Gateway",
        "to": "Search & Discovery Service",
        "contract": "REST — GET /restaurants?q=&lat=&lng=&filters=",
        "coupling_type": "runtime (synchronous)"
      },
      {
        "from": "Order Service",
        "to": "Payment Service",
        "contract": "Synchronous call for payment authorization during checkout; async events for capture/refund",
        "coupling_type": "runtime (synchronous for auth, async for settlement)"
      },
      {
        "from": "Order Service",
        "to": "Restaurant Service",
        "contract": "OrderPlaced event consumed by Restaurant Service to trigger acceptance flow",
        "coupling_type": "async (domain event via message broker)"
      },
      {
        "from": "Order Service",
        "to": "Delivery Service",
        "contract": "OrderReady event triggers driver matching and assignment",
        "coupling_type": "async (domain event via message broker)"
      },
      {
        "from": "Delivery Service",
        "to": "Order Service",
        "contract": "DriverAssigned, DeliveryCompleted events update order state",
        "coupling_type": "async (domain event via message broker)"
      },
      {
        "from": "Restaurant Service",
        "to": "Search & Discovery Service",
        "contract": "MenuUpdated, RestaurantOnline/Offline events rebuild search index",
        "coupling_type": "async (domain event via message broker)"
      },
      {
        "from": "All Services",
        "to": "Notification Service",
        "contract": "Domain events (OrderPlaced, DriverAssigned, OrderDelivered, etc.) trigger notifications",
        "coupling_type": "async (fan-out via message broker)"
      },
      {
        "from": "Order Service",
        "to": "Pricing & Promotions Service",
        "contract": "Synchronous call — POST /price-calculation with cart, location, promo code",
        "coupling_type": "runtime (synchronous)"
      },
      {
        "from": "Delivery Service",
        "to": "API Gateway (WebSocket)",
        "contract": "Real-time driver location stream via WebSocket to customer and restaurant apps",
        "coupling_type": "runtime (streaming)"
      }
    ],
    "data_flow": "1) Customer searches restaurants (Search Service → read model). 2) Customer places order (Order Service creates order, calls Pricing Service for total, calls Payment Service for authorization). 3) OrderPlaced event fires → Restaurant Service presents to restaurant for acceptance. 4) Restaurant accepts → OrderAccepted event → Customer notified. 5) Restaurant marks food ready → OrderReady event → Delivery Service runs matching algorithm, assigns nearest available driver → DriverAssigned event. 6) Driver picks up → real-time location streams to customer via WebSocket. 7) Driver confirms delivery → DeliveryCompleted event → Order Service marks complete → Payment Service captures payment → Rating prompts sent.",
    "patterns_used": [
      {
        "pattern": "Event-Driven Architecture with Domain Events",
        "rationale": "The three-sided marketplace requires loose coupling between Restaurant, Delivery, and Order contexts. Events allow each side to evolve independently and react to state changes without direct dependencies."
      },
      {
        "pattern": "Saga (Orchestration) for Order Lifecycle",
        "rationale": "An order spans multiple services (payment, restaurant, delivery). The Order Service acts as the saga orchestrator, coordinating the multi-step process and handling compensating transactions (refunds on cancellation, driver reassignment on timeout)."
      },
      {
        "pattern": "CQRS for Search & Discovery",
        "rationale": "Restaurant search requires a denormalized, optimized read model (by location, cuisine, rating, availability) that is fundamentally different from the write model. CQRS lets us optimize reads independently."
      },
      {
        "pattern": "Anti-Corruption Layer for Payment Integration",
        "rationale": "External payment providers (Stripe, etc.) have their own models and can change APIs. An ACL translates between our domain language and the provider's, protecting our domain model from external pollution."
      },
      {
        "pattern": "Strangler Fig (future migration path)",
        "rationale": "If starting as a modular monolith, services can be extracted one at a time behind the event bus. The event-driven boundaries make this extraction straightforward."
      },
      {
        "pattern": "Location-Based Sharding for Delivery",
        "rationale": "Driver matching is inherently geographic. Partitioning delivery state by geographic region enables horizontal scaling and keeps matching algorithms operating on local data."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root: OrderId; entities: OrderItem, OrderStatusHistory; values: DeliveryAddress, OrderTotal, Tip)",
          "Cart (root: CartId; values: CartItem, CartTotal — ephemeral, pre-order)"
        ]
      },
      {
        "name": "Restaurant",
        "classification": "supporting",
        "aggregates": [
          "Restaurant (root: RestaurantId; entities: Menu, MenuItem; values: OperatingHours, Location, CuisineType)",
          "RestaurantOrder (root: RestaurantOrderId; values: PrepTimeEstimate, AcceptanceStatus — restaurant's view of an order)"
        ]
      },
      {
        "name": "Delivery",
        "classification": "core",
        "aggregates": [
          "Driver (root: DriverId; values: DriverLocation, AvailabilityStatus, VehicleType)",
          "Delivery (root: DeliveryId; values: PickupLocation, DropoffLocation, EstimatedArrival, DeliveryStatus, Route)"
        ]
      },
      {
        "name": "Pricing",
        "classification": "core",
        "aggregates": [
          "PriceCalculation (root: CalculationId; values: BaseFee, SurgeFactor, DeliveryFee, ServiceFee, Discount)",
          "Promotion (root: PromoId; values: PromoCode, DiscountRule, ValidityPeriod, UsageLimit)"
        ]
      },
      {
        "name": "Payment",
        "classification": "generic",
        "aggregates": [
          "PaymentTransaction (root: TransactionId; values: Amount, Currency, PaymentMethod, TransactionStatus)",
          "Payout (root: PayoutId; values: RecipientId, RecipientType, Amount, PayoutSchedule)"
        ]
      },
      {
        "name": "Identity & Customer",
        "classification": "generic",
        "aggregates": [
          "UserAccount (root: UserId; values: Email, PhoneNumber, Role, AuthCredentials)",
          "CustomerProfile (root: CustomerId; entities: SavedAddress; values: Preferences, PaymentMethods)"
        ]
      },
      {
        "name": "Rating & Review",
        "classification": "supporting",
        "aggregates": [
          "Review (root: ReviewId; values: Rating, Comment, ReviewTarget, ReviewerInfo)"
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Restaurant",
        "relationship": "Customer-Supplier — Order Management publishes order events; Restaurant context consumes and adapts to its own RestaurantOrder model."
      },
      {
        "upstream": "Order Management",
        "downstream": "Delivery",
        "relationship": "Customer-Supplier — Order Management signals when pickup is needed; Delivery context owns driver matching independently."
      },
      {
        "upstream": "Pricing",
        "downstream": "Order Management",
        "relationship": "Open Host Service — Pricing exposes a published calculation API; Order Management conforms to pricing results."
      },
      {
        "upstream": "Order Management",
        "downstream": "Payment",
        "relationship": "Customer-Supplier with ACL — Order Management requests payment operations; Payment wraps external provider behind anti-corruption layer."
      },
      {
        "upstream": "Restaurant",
        "downstream": "Search & Discovery (within Restaurant context)",
        "relationship": "Published Language — Restaurant publishes menu/availability in a canonical format consumed by the search read model."
      },
      {
        "upstream": "Identity & Customer",
        "downstream": "All Contexts",
        "relationship": "Shared Kernel (minimal) — UserId is the shared identity token across all contexts. Each context stores only the user attributes it needs."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Event-driven async communication between core services instead of synchronous REST calls",
      "gains": "Loose coupling, independent deployability, natural resilience (services can recover from downtime by replaying events), better scalability for spiky food ordering patterns",
      "sacrifices": "Eventual consistency (customer might briefly see stale order status), operational complexity of message broker, harder to debug end-to-end flows, requires idempotency everywhere",
      "alternatives_considered": [
        "Fully synchronous microservices — simpler to reason about but creates a distributed monolith with cascading failures",
        "Monolith-first — lower initial complexity but harder to scale the delivery matching independently from order processing"
      ]
    },
    {
      "decision": "Order Service as saga orchestrator rather than choreography",
      "gains": "Centralized visibility into order lifecycle, easier to implement timeouts and compensating transactions (e.g., refund if restaurant rejects), simpler debugging of failed orders",
      "sacrifices": "Order Service becomes a coordination bottleneck and a more complex component, tighter logical coupling to the order workflow",
      "alternatives_considered": [
        "Pure choreography — more decoupled but order lifecycle becomes invisible, scattered across services, very hard to debug 'where is my order?' issues"
      ]
    },
    {
      "decision": "Separate Delivery Service with its own matching algorithm rather than embedding in Order Service",
      "gains": "Driver matching is a complex, independently evolving algorithm (ML-based optimization, surge handling, fairness). Isolating it allows the delivery team to iterate without touching order logic.",
      "sacrifices": "Additional network hop and potential latency in driver assignment, more operational overhead",
      "alternatives_considered": [
        "Embed matching in Order Service — fewer services but conflates order lifecycle with real-time geospatial operations"
      ]
    },
    {
      "decision": "Start as a modular monolith with event-driven internal boundaries, extract to microservices as scale demands",
      "gains": "Dramatically lower operational complexity at launch, easier local development, simple deployment, can still extract services later because boundaries are clean",
      "sacrifices": "Single deployment unit means all contexts share a release cycle initially, shared database requires discipline to respect context boundaries",
      "alternatives_considered": [
        "Microservices from day one — proper physical isolation but massive operational overhead for a team that hasn't yet proven product-market fit"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Driver matching algorithm",
      "evolution_path": "Start with simple nearest-available-driver. Evolve to ML-based optimization considering driver preferences, estimated prep time, batching multiple orders, and fairness scoring. The Delivery bounded context isolates this evolution."
    },
    {
      "area": "Payment provider",
      "evolution_path": "ACL around payment provider means swapping Stripe for Adyen (or adding multiple providers for geographic expansion) requires changes only inside the Payment context."
    },
    {
      "area": "Search and ranking",
      "evolution_path": "CQRS read model allows the search/ranking algorithm to evolve independently — from simple distance+rating to personalized ML recommendations — without touching restaurant write model."
    },
    {
      "area": "Pricing model",
      "evolution_path": "Isolated Pricing context supports evolution from flat delivery fees → dynamic surge pricing → subscription models (e.g., free delivery pass) → restaurant-subsidized promotions."
    },
    {
      "area": "Notification channels",
      "evolution_path": "Event-driven Notification Service can add channels (push, SMS, email, in-app) without modifying any upstream service."
    }
  ],

  "rigidity_points": [
    {
      "area": "Order state machine",
      "reason": "The order lifecycle (Placed → Accepted → Preparing → Ready → PickedUp → Delivered) is the backbone of the platform. Changes here cascade to every context. This rigidity is intentional — the order state machine IS the business."
    },
    {
      "area": "UserId as shared identity",
      "reason": "Every context references UserId. Changing the identity model would require coordinated changes across all contexts. Accept this coupling — identity is a natural shared kernel."
    },
    {
      "area": "Domain event schema",
      "reason": "Published events are contracts. Once consumers depend on OrderPlaced v1, schema changes require versioning and backward compatibility. Use schema evolution (add fields, never remove) from day one."
    }
  ],

  "risks": [
    {
      "risk": "Order saga failure leaves system in inconsistent state (e.g., payment authorized but restaurant never notified)",
      "severity": "critical",
      "mitigation": "Implement saga with explicit compensating transactions. Every step has a defined rollback. Use a persistent saga log (outbox pattern) so recovery survives service restarts. Add dead-letter queues and alerting for stuck orders."
    },
    {
      "risk": "Real-time driver location tracking creates high write throughput that overwhelms traditional databases",
      "severity": "high",
      "mitigation": "Use Redis or a specialized geospatial store for hot driver location data. Batch location updates (every 5s, not every 1s). Shard by geographic region. Persist to durable store asynchronously for analytics."
    },
    {
      "risk": "Surge pricing and delivery fee calculation becomes a latency bottleneck in the checkout path",
      "severity": "medium",
      "mitigation": "Cache pricing factors aggressively (surge multiplier changes every few minutes, not per-request). Pre-calculate and push surge zones rather than computing per-request. Set aggressive timeouts with fallback to base pricing."
    },
    {
      "risk": "Event ordering issues cause incorrect state transitions (e.g., DeliveryCompleted arrives before DriverAssigned due to race condition)",
      "severity": "high",
      "mitigation": "Partition events by OrderId to guarantee per-order ordering. Include sequence numbers in events. Consumers must be idempotent and handle out-of-order delivery gracefully."
    },
    {
      "risk": "Modular monolith boundaries erode over time — developers take shortcuts across context boundaries",
      "severity": "medium",
      "mitigation": "Enforce module boundaries via package-level access control (e.g., Java modules, Go internal packages, ArchUnit tests). CI checks that detect cross-boundary imports. Code review culture."
    },
    {
      "risk": "Three-sided marketplace cold start — no drivers without orders, no orders without restaurants, no customers without both",
      "severity": "high",
      "mitigation": "Not strictly architectural, but the system should support manual/admin overrides for early operations: manually assign drivers, seed restaurant data, offer guaranteed driver minimums. Build admin tooling as a first-class concern."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Start as a modular monolith with clean bounded context boundaries enforced at the module/package level. Use an in-process event bus (e.g., Spring ApplicationEvents, Node.js EventEmitter with async handlers, or a lightweight message queue like BullMQ) that can be swapped for Kafka/RabbitMQ when extracting to microservices. Build the Order saga orchestrator first — it's the critical path. Deploy a single service initially, extract Delivery Service first (highest independent scaling need due to real-time location), then Search, then others as needed.",
    "files_to_create_or_modify": [
      "src/order/ — Order aggregate, OrderSaga, OrderService, OrderRepository, order events",
      "src/restaurant/ — Restaurant aggregate, Menu entity, RestaurantService, menu events",
      "src/delivery/ — Driver aggregate, Delivery aggregate, MatchingAlgorithm, location tracker",
      "src/pricing/ — PriceCalculator, SurgeEngine, PromotionService",
      "src/payment/ — PaymentGateway (ACL interface), PaymentService, payout scheduler",
      "src/customer/ — CustomerProfile, AddressBook, PreferencesService",
      "src/notification/ — NotificationRouter, templates, channel adapters (push/sms/email)",
      "src/search/ — SearchIndex, RestaurantProjection, RankingAlgorithm",
      "src/shared/events/ — Event base types, event bus interface, outbox table",
      "src/shared/identity/ — UserId value object, auth middleware (shared kernel)",
      "src/api/ — API Gateway routes, request validation, rate limiting middleware",
      "infrastructure/ — Docker compose, database migrations, message broker config"
    ],
    "patterns_to_follow": "Aggregate pattern for all write models (enforce invariants at aggregate boundaries). Repository pattern for persistence (one repo per aggregate root). Domain events published via outbox pattern for reliability. CQRS for search (separate read model). Anti-corruption layer for all external integrations. Value objects for immutable domain concepts (Money, Location, Address). Rich domain model — push logic into aggregates, not services.",
    "pitfalls_to_avoid": [
      "Do NOT share database tables across bounded contexts — each context owns its data, even in a monolith. Use separate schemas or table prefixes.",
      "Do NOT make the Order Service call Delivery Service synchronously for driver assignment — this couples the order completion path to driver availability and creates cascading failures.",
      "Do NOT store driver location in a relational database — it's high-frequency write, low-durability-requirement data. Use Redis GEO or similar.",
      "Do NOT build a generic 'event store' from scratch — use a battle-tested message broker. Event sourcing is overkill here; simple domain events with outbox pattern are sufficient.",
      "Do NOT skip idempotency on event handlers — in a distributed system, events WILL be delivered more than once.",
      "Do NOT put business logic in the API Gateway — it should be a thin routing/auth layer only."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "Bounded context boundaries — the three-sided marketplace naturally decomposes into Order, Restaurant, Delivery, and Payment contexts",
      "Event-driven communication between contexts — well-established pattern for marketplace platforms",
      "Saga orchestration for order lifecycle — proven approach used by major food delivery platforms",
      "CQRS for search — standard pattern for read-heavy discovery workloads"
    ],
    "low_confidence_areas": [
      "Exact driver matching algorithm design — depends heavily on market density, driver supply, and business rules not yet specified",
      "Surge pricing model specifics — requires business input on pricing strategy and competitive dynamics",
      "Scale requirements — the decision of when to extract from monolith to microservices depends on actual traffic patterns and team size",
      "Real-time infrastructure choices (WebSocket vs SSE vs polling) — depends on client platform constraints and latency requirements"
    ],
    "assumptions": [
      "Team is small-to-medium (5-20 engineers) — hence modular monolith first recommendation",
      "Single geographic market at launch, expanding later",
      "Standard three-sided marketplace model (customer pays, restaurant prepares, driver delivers)",
      "Mobile-first clients (iOS/Android) with a web dashboard for restaurants",
      "Payment processing will use a third-party provider, not built in-house"
    ]
  }
}
